{
  "name": "Program of All-Inclusive Care for the Elderly (PACE) - Limited Availability in Idaho",
  "eligibility": {
    "age": null,
    "income_limits": "No PACE programs operate in Idaho, so no income limits apply. Nationally, PACE targets dually eligible Medicare/Medicaid individuals with no specific dollar amounts listed for Idaho.[2][8]",
    "asset_limits": "No asset limits apply in Idaho due to lack of programs. National PACE does not specify asset tests in available data.[2]",
    "other_requirements": ["No PACE programs available in Idaho, so no eligibility requirements apply.[1]", "Nationally: Age 55+, nursing facility eligible level of care, able to live safely in community with PACE services, reside in PACE service area.[2][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "No benefits available in Idaho. Nationally: Comprehensive medical and social services including primary care, hospitalization, prescription drugs, social services, therapeutic activities, minor home modifications, home care, durable medical equipment for frail elderly living in community.[2]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["No application methods in Idaho due to no programs.[1]", "Nationally: Contact local PACE organization via NPA finder tool.[1]"],
    "processing_time": "Not applicable in Idaho",
    "waitlist": "Not applicable in Idaho",
    "forms": ["No specific forms for Idaho.[1]"],
    "documents": ["No documents needed in Idaho.[1]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "No PACE programs anywhere in Idaho.[1]",
    "regional_variations": "No programs, so no variations.[1]",
    "offices_or_providers": []
  },
  "official_source": "https://www.npaonline.org/find-a-pace-program (confirms no Idaho programs); https://www.cms.gov/medicare/medicaid-coordination/about/pace[1][2]",
  "gotchas": ["PACE does not exist in Idaho—search confirms zero programs despite national availability in 33 states.[1]", "Do not confuse with Idaho's C-PACE (Commercial Property Assessed Clean Energy financing for buildings).[3][4][5][6][7][9][10]", "Families must explore alternatives like Idaho Medicaid Home and Community-Based Services (HCBS) waivers.", "Limited to community-living frail elderly nationally; requires nursing home level of care certification.[2][8]"],
  "data_shape_notes": "no programs available in Idaho; national PACE is provider-specific and geographically restricted; search results polluted with unrelated commercial C-PACE financing programs active in cities like Boise, Coeur d'Alene, Rexburg.[1][3][4][5]"
}

{
  "name": "Medicare Savings Programs (QMB, SLMB, QI)",
  "eligibility": {
    "age": null,
    "income_limits": "Must be entitled to Medicare Part A (even if not enrolled). Income limits for Idaho (2024 figures from state-specific source; federal 2026 standards are higher at QMB individual $1,350/month, but use current state-verified): QMB: $1,235 single/$1,663 couple; SLMB: $1,478 single/$1,992 couple; QI: $1,660 single/$2,239 couple. Limits based on % FPL (100% QMB, 120% SLMB, 135% QI) and updated annually in April. No variation by larger household sizes shown; typically individual or couple[2][6][7].",
    "asset_limits": "Federal limits apply in Idaho: $9,090 single/$13,630 couple across QMB/SLMB/QI. Counts: bank accounts, stocks, bonds. Exempt: home, one car, burial plots, life insurance (up to $1,500 face value), personal belongings[2][5].",
    "other_requirements": ["Entitled to Medicare Part A (premium-free or not)", "Idaho resident", "U.S. citizen or qualified immigrant"]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Medicare Part A premiums (if applicable), Part B premiums/deductible, Part A/B coinsurance/copays/deductibles. SLMB: Part B premiums only. QI: Part B premiums only (auto-qualifies for Extra Help low-income subsidy for drugs, $12.65 max copay/drug in 2026)[1][2][6][7].",
    "varies_by": "program_tier"
  },
  "application": {
    "methods": ["Phone: Contact Idaho DHW at regional offices or SHIBA 1-800-247-4422", "Website: healthandwelfare.idaho.gov/services-programs/medicaid-health/medicare-savings-program (request application)", "Mail/In-person: Local DHW Medicaid offices (find via healthandwelfare.idaho.gov/locations)"],
    "processing_time": "QMB: Up to 45 days, effective first of month after complete info. SLMB/QI: Up to 3 months retroactive[1].",
    "waitlist": "QI has first-come-first-served with priority to prior recipients; potential waitlist if funding limited[7].",
    "forms": ["Medicaid application (MSP-specific form requested from state Medicaid agency/DHW)"],
    "documents": ["Proof of income (SSI award, pay stubs, tax return)", "Proof of resources (bank statements)", "Medicare card", "ID (birth certificate, SSN)", "Proof of residency"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly statewide by Idaho DHW, but apply via local/regional offices; no noted differences in eligibility/benefits[6].",
    "offices_or_providers": ["Idaho Department of Health and Welfare regional offices (locations at healthandwelfare.idaho.gov/locations)"]
  },
  "official_source": "https://healthandwelfare.idaho.gov/services-programs/medicaid-health/medicare-savings-program",
  "gotchas": ["Income/asset limits updated yearly (April); verify current FPL-based amounts as search shows variance (e.g., 2024 vs 2026 federal)", "QI requires annual reapplication, first-come-first-served, possible funding caps", "Must have Part A entitlement; QMB protects from provider billing for copays (no balance billing)", "States can be more generous (Idaho uses federal asset limits)"],
  "data_shape_notes": "Tiered by program (QMB/SLMB/QI) with escalating income thresholds; couple limits ~1.35x single; assets fixed federal minimums; QI funding-limited"
}

{
  "name": "Senior Health Insurance Benefit Advisors (SHIBA) Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Idaho residents needing Medicare counseling[1][2][3]",
    "asset_limits": "No asset limits; no financial tests apply[1][3]",
    "other_requirements": ["Idaho resident", "Typically seniors or disabled individuals with Medicare questions, but no strict requirements stated[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one health insurance counseling, information and printed materials, referrals to agencies; covers Medicare Parts A/B/D, Medigap, Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, and other programs; helps understand benefits, compare options, avoid overpaying[1][2][3]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-247-4422[2][4][5]", "Online form: https://doi.idaho.gov/shiba/[4]", "Email: Shannon.Hohl@doi.idaho.gov[2]", "In-person or phone appointments available statewide via counselors in every county[3][4]"],
    "processing_time": "Not specified; appointments scheduled upon contact[1][4]",
    "waitlist": null,
    "forms": ["Online contact form on https://doi.idaho.gov/shiba/[4]"],
    "documents": ["No specific documents required for initial counseling; may need Medicare card or insurance details for detailed advice[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Counselors trained and available in every county, but delivered through local volunteers; no differences in services noted[3]",
    "offices_or_providers": ["Main office: Idaho Department of Insurance, 700 West State St., 3rd Floor, Boise ID 83720; local counselors statewide[2][3]"]
  },
  "official_source": "https://doi.idaho.gov/shiba/[2][4]",
  "gotchas": ["Not an insurance seller or policy recommender—provides unbiased info only[3]", "Free service, but users may confuse it with paid advising or direct benefits enrollment[1][3]", "Relies on volunteer counselors, so availability may depend on local scheduling[3]", "Focused solely on Medicare/health insurance navigation, not direct healthcare or financial aid[1]"],
  "data_shape_notes": "no income or asset test; counseling service only via statewide volunteer network in every county; not a benefit-paying program"
}

{
  "name": "Family Caregiver Support Program (FCSP)",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits specified for FCSP itself; caregivers support care recipients aged 60+ or with Alzheimer's (any age). Related Medicaid PCS (often required for services): single $1,047/month, couple $1,511/month.[1]",
    "asset_limits": "No asset limits specified for FCSP. For related Medicaid PCS: home exempt if applicant, spouse, minor child, or blind/disabled child lives there; other assets counted under Medicaid rules.[1]",
    "other_requirements": ["Caregiver must be adult family member or informal caregiver for individual 60+ or with Alzheimer's/related disorders.", "Care recipient must demonstrate functional need (e.g., assistance with ADLs/IADLs like bathing, dressing, meal prep).", "Services often tied to Medicaid eligibility for care recipient in Idaho implementations.[3][9]"]
  },
  "benefits": {
    "type": "service",
    "value": "Information, assistance, respite care, caregiver training, counseling, and support groups; no direct cash payments to family caregivers in Idaho. Specific hours/dollars not fixed statewide; varies by local AAA funding and needs assessment.[3][9]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) via Idaho Commission on Aging: aging.idaho.gov or 208-334-3833.", "No specific online form or central phone listed; regional AAAs handle intake (e.g., in-person, phone).[9]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Possible due to funding limits; varies regionally.",
    "forms": ["No specific FCSP form named; uses Uniform Assessment Instrument (UAI) for functional needs in related assessments.[1]"],
    "documents": ["Proof of relationship to care recipient.", "Care recipient's functional assessment details (ADLs/IADLs).", "Medicaid eligibility docs if applicable (income verification, assets).[1][9]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through 7 regional Area Agencies on Aging (AAAs) covering all Idaho counties.",
    "regional_variations": "Services, availability, wait times, and providers differ by AAA region; contact local AAA for specifics.[9]",
    "offices_or_providers": ["Area Agencies on Aging via Idaho Commission on Aging (aging.idaho.gov)."]
  },
  "official_source": "https://aging.idaho.gov/stay-at-home/national-family-caregiver-support-program/",
  "gotchas": ["Idaho does not pay family caregivers directly via FCSP; must use Medicaid-approved agencies or Certified Family Homes for payment (care recipient needs Medicaid).[2][4]", "Often confused with Medicaid PCS, which funds services but not direct family pay.[1][5]", "No statewide fixed hours/dollars; limited by federal OAA funding and local resources.[3][9]", "Functional need required, not just age or diagnosis.[1]"],
  "data_shape_notes": "Federally funded via OAA, locally administered by AAAs with no direct payments; services vary regionally and often require Medicaid linkage for paid in-home care; no income/asset test for core FCSP but applies to tied programs."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; program is free and open to all eligible residents regardless of financial status.",
    "asset_limits": "No asset limits or tests; no financial qualifications required.",
    "other_requirements": ["Resident of a long-term care facility (e.g., skilled nursing, rehabilitation, assisted living, residential care facilities) in Idaho.", "Complaints made by or on behalf of residents aged 60 or older.", "Also available to families, friends, concerned staff, or any person/group worried about resident treatment.", "Online reporting limited to mandated reporters (e.g., physicians, nurses, law enforcement) or financial institutions; others must call local Area Agency on Aging."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigates complaints about health, safety, welfare, and rights; provides advocacy on resident care issues (e.g., rehabilitation, restraints, maintenance of function); offers information, education, referrals on long-term care and benefits; conducts routine facility visits, attends resident council meetings; participates in licensure surveys; resolves issues in nursing homes, assisted living, skilled nursing, and rehabilitation facilities.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact State Ombudsman at Idaho Commission on Aging or local Area Agency on Aging (specific regional numbers, e.g., Area Agency on Aging of North Idaho or CSI Office on Aging at 208-736-2122 or 1-800-574-8656).", "Online: Limited to mandated reporters via designated online report form.", "In-person: Local Ombudsman at Area Agencies on Aging.", "Note: No specific application form; report complaints directly by phone or online for eligible reporters."],
    "processing_time": "Not specified; immediate access to residents permitted, investigations handled promptly during business hours.",
    "waitlist": null,
    "forms": ["No formal application forms; complaint reporting via phone or online for mandated reporters."],
    "documents": ["No documents required for reporting complaints; provide details of the concern (e.g., resident name, facility, issue description)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to long-term care facilities (nursing homes, assisted living, skilled nursing, rehabilitation); some programs note limited home care advocacy.",
    "regional_variations": "Administered through regional Area Agencies on Aging with local ombudsmen (e.g., Area Agency on Aging of North Idaho, CSI Office on Aging serving specific facilities); different contact numbers and offices by region, but core services consistent statewide.",
    "offices_or_providers": ["Idaho Commission on Aging (State Ombudsman).", "Area Agency on Aging of North Idaho.", "CSI Office on Aging (208-736-2122 or 1-800-574-8656).", "Other local Area Agencies on Aging."]
  },
  "official_source": "https://aging.idaho.gov/ombudsman-program/",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, financial aid, or personal care); focuses solely on advocacy and complaint resolution.", "Online reporting only for mandated reporters; families must call local office.", "Limited to facility residents aged 60+; does not typically cover home care except in limited cases.", "Volunteers/ombudsmen undergo background checks, but reporters do not.", "Anyone can report, but access to residents requires facility permission and resident consent."],
  "data_shape_notes": "no income test; advocacy-only for facility residents via regional Area Agencies on Aging; complaint-driven, not application-based enrollment"
}
